import React, { useState, useEffect, useRef } from 'react';

const LOGO = process.env.PUBLIC_URL + '/logo.png';

function useCountUp(target, duration = 2000, start = false) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!start) return;
    let startTime = null;
    const step = (ts) => {
      if (!startTime) startTime = ts;
      const progress = Math.min((ts - startTime) / duration, 1);
      setVal(Math.floor(progress * target));
      if (progress < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [start, target, duration]);
  return val;
}

function useInView(ref, threshold = 0.2) {
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [ref, threshold]);
  return inView;
}

function Icon({ name, size = 24, style = {} }) {
  return (
    <span className="material-symbols-outlined" style={{ fontSize: size, lineHeight: 1, ...style }}>
      {name}
    </span>
  );
}

function StatCounter({ value, suffix = '', label, inView }) {
  const num = useCountUp(value, 1800, inView);
  return (
    <div style={{ textAlign: 'center', padding: '0 24px' }}>
      <div style={{ fontSize: 48, fontWeight: 900, color: '#fff', fontFamily: 'Manrope,sans-serif', lineHeight: 1 }}>
        {num}{suffix}
      </div>
      <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.6)', marginTop: 8, fontWeight: 600, letterSpacing: '0.05em' }}>{label}</div>
    </div>
  );
}

export default function LandingPage() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [popup, setPopup] = useState(false);
  const [regModal, setRegModal] = useState(false);
  const [regForm, setRegForm] = useState({ name: '', phone: '', email: '' });
  const [regErrors, setRegErrors] = useState({});
  const [regDone, setRegDone] = useState(false);
  const [regLoading, setRegLoading] = useState(false);

  const handleRegSubmit = async (e) => {
    e.preventDefault();
    const errs = {};
    if (!regForm.name.trim()) errs.name = 'Name is required';
    if (!regForm.phone.trim()) errs.phone = 'Phone number is required';
    else if (!/^[6-9]\d{9}$/.test(regForm.phone.trim())) errs.phone = 'Enter a valid 10-digit mobile number';
    if (regForm.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(regForm.email)) errs.email = 'Enter a valid email';
    setRegErrors(errs);
    if (Object.keys(errs).length > 0) return;
    setRegLoading(true);
    try {
      await fetch('http://localhost:5001/api/admissions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name: regForm.name.trim(), phone: regForm.phone.trim(), email: regForm.email.trim() }),
      });
    } catch (_) { /* still show success even if offline */ }
    setRegLoading(false);
    setRegDone(true);
  };

  const closeReg = () => { setRegModal(false); setRegDone(false); setRegForm({ name: '', phone: '', email: '' }); setRegErrors({}); };
  const statsRef = useRef(null);
  const aboutRef = useRef(null);
  const valuesRef = useRef(null);
  const facilitiesRef = useRef(null);
  const contactRef = useRef(null);
  const statsInView = useInView(statsRef);
  const aboutInView = useInView(aboutRef);
  const valuesInView = useInView(valuesRef);
  const contactInView = useInView(contactRef);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    const t = setTimeout(() => setPopup(true), 5000);
    return () => clearTimeout(t);
  }, []);

  const scrollTo = (id) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
    setMenuOpen(false);
  };

  const NAV_LINKS = [
    { label: 'About', id: 'about' },
    { label: 'Academics', id: 'academics' },
    { label: 'Notices', id: 'notices' },
    { label: 'Contact', id: 'contact' },
  ];

  const VALUES = [
    { icon: 'menu_book', title: 'Quality Education', desc: 'Rigorous academics with a focus on conceptual clarity and critical thinking.', grad: 'linear-gradient(135deg,#3b82f6,#6366f1)' },
    { icon: 'directions_run', title: 'Physical Education', desc: 'Sports and fitness programs to build healthy, disciplined minds and bodies.', grad: 'linear-gradient(135deg,#10b981,#059669)' },
    { icon: 'eco', title: 'Moral Values', desc: 'Character building through ethics, integrity, and community service.', grad: 'linear-gradient(135deg,#f59e0b,#ef4444)' },
    { icon: 'groups', title: 'Social Development', desc: 'Collaborative learning that prepares students for a diverse world.', grad: 'linear-gradient(135deg,#8b5cf6,#ec4899)' },
  ];



  const NOTICES = [
    { date: 'Mar 20, 2026', title: 'Annual Sports Day — Registration Open', tag: 'Event' },
    { date: 'Mar 15, 2026', title: 'Summer Vacation Schedule Announced', tag: 'Notice' },
    { date: 'Mar 10, 2026', title: 'Parent-Teacher Meeting — April 5, 2026', tag: 'Notice' },
    { date: 'Mar 05, 2026', title: 'Admission Open for Session 2026-2027', tag: 'Admission' },
    { date: 'Feb 28, 2026', title: 'Annual Results Declared — 100% Pass Rate', tag: 'Result' },
  ];

  const tagColor = { Event: '#3b82f6', Exam: '#8b5cf6', Notice: '#f59e0b', Admission: '#10b981', Result: '#ef4444' };

  const LOGIN_ROLES = [
    { icon: 'admin_panel_settings', label: 'Admin Login', desc: 'Full management access', grad: 'linear-gradient(135deg,#1960a3,#3b82f6)' },
    { icon: 'school', label: 'Teacher Login', desc: 'Attendance & marks', grad: 'linear-gradient(135deg,#059669,#10b981)' },
    { icon: 'family_restroom', label: 'Parent Login', desc: 'Track your child', grad: 'linear-gradient(135deg,#7c3aed,#8b5cf6)' },
  ];

  return (
    <div style={{ fontFamily: 'Inter, sans-serif', color: '#1e293b', background: '#fff', overflowX: 'hidden' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;600;700;800;900&family=Inter:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        html { scroll-behavior: smooth; }

        .lp-nav-link {
          cursor: pointer; font-weight: 600; font-size: 14px;
          transition: color 200ms; position: relative; padding-bottom: 4px;
        }
        .lp-nav-link::after {
          content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 2px;
          background: #1960a3; border-radius: 2px; transition: width 250ms ease;
        }
        .lp-nav-link:hover::after { width: 100%; }
        .lp-nav-link:hover { color: #1960a3 !important; }

        .lp-card { transition: transform 250ms cubic-bezier(0.34,1.56,0.64,1), box-shadow 250ms; }
        .lp-card:hover { transform: translateY(-6px); box-shadow: 0 20px 48px rgba(0,32,69,0.14) !important; }

        .lp-btn-primary {
          background: linear-gradient(135deg,#002045,#1960a3); color: #fff; border: none;
          border-radius: 12px; padding: 14px 32px; font-size: 15px; font-weight: 700;
          cursor: pointer; transition: all 250ms; font-family: inherit;
          box-shadow: 0 4px 16px rgba(25,96,163,0.25);
        }
        .lp-btn-primary:hover { transform: translateY(-2px); box-shadow: 0 10px 28px rgba(25,96,163,0.45); }

        .lp-btn-outline {
          background: transparent; color: #fff; border: 2px solid rgba(255,255,255,0.5);
          border-radius: 12px; padding: 13px 28px; font-size: 15px; font-weight: 700;
          cursor: pointer; transition: all 250ms; font-family: inherit;
        }
        .lp-btn-outline:hover { background: rgba(255,255,255,0.12); border-color: #fff; transform: translateY(-2px); }

        @keyframes lp-fade-up { from { opacity:0; transform:translateY(32px); } to { opacity:1; transform:none; } }
        @keyframes lp-float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-14px)} }
        @keyframes lp-spin-slow { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes pop-in { from{opacity:0;transform:scale(0.88) translateY(20px)} to{opacity:1;transform:none} }

        .lp-hero-text { animation: lp-fade-up 800ms 200ms both; }
        .lp-hero-sub  { animation: lp-fade-up 800ms 400ms both; }
        .lp-hero-btns { animation: lp-fade-up 800ms 600ms both; }

        .lp-section { padding: 88px 0; }
        .lp-container { max-width: 1200px; margin: 0 auto; padding: 0 24px; }
        .lp-grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 56px; align-items: center; }
        .lp-grid-3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 24px; }
        .lp-grid-4 { display: grid; grid-template-columns: repeat(4,1fr); gap: 24px; }

        @media(max-width:900px){
          .lp-grid-2{grid-template-columns:1fr;}
          .lp-grid-3{grid-template-columns:1fr 1fr;}
          .lp-grid-4{grid-template-columns:1fr 1fr;}
        }
        @media(max-width:600px){
          .lp-grid-3,.lp-grid-4{grid-template-columns:1fr;}
          .lp-hero-title{font-size:36px!important;}
          .lp-stats-grid{grid-template-columns:1fr 1fr!important;}
        }

        .lp-section-label { font-size: 11px; font-weight: 800; color: #1960a3; letter-spacing: 0.2em; text-transform: uppercase; margin-bottom: 12px; display: flex; align-items: center; gap: 8px; }
        .lp-section-label::before { content:''; display:inline-block; width:20px; height:2px; background:#1960a3; border-radius:2px; }
        .lp-section-title { font-size: 38px; font-weight: 900; color: #1e293b; font-family: Manrope,sans-serif; line-height: 1.15; margin-bottom: 16px; }
        .lp-section-desc { font-size: 15px; color: #64748b; line-height: 1.8; }

        .lp-icon-box {
          width: 56px; height: 56px; border-radius: 16px; display: flex; align-items: center;
          justify-content: center; margin-bottom: 20px; flex-shrink: 0;
          box-shadow: 0 8px 20px rgba(0,0,0,0.15);
        }

        .notice-row { transition: background 150ms; }
        .notice-row:hover { background: #f8fafc !important; }

        .lp-fade-in { opacity: 0; transform: translateY(24px); transition: opacity 600ms ease, transform 600ms ease; }
        .lp-fade-in.visible { opacity: 1; transform: none; }

        .role-card {
          padding: 20px 24px; border-radius: 16px; border: 1.5px solid rgba(255,255,255,0.15);
          background: rgba(255,255,255,0.06); color: #fff; cursor: pointer;
          transition: all 250ms; font-family: inherit; text-align: left; display: flex; align-items: center; gap: 16px;
        }
        .role-card:hover { background: rgba(255,255,255,0.12); border-color: rgba(255,255,255,0.35); transform: translateY(-3px); box-shadow: 0 12px 32px rgba(0,0,0,0.3); }

        .reg-input { width: 100%; padding: 11px 14px; border-radius: 10px; border: 1.5px solid #e2e8f0; background: #f8fafc; font-size: 14px; color: #1e293b; outline: none; transition: border 150ms; font-family: inherit; }
