              </div>
              <div>
                <div style={{ fontSize: 13, fontWeight: 800, color: '#fff', fontFamily: 'Manrope,sans-serif' }}>LORD KRISHNA PUBLIC SCHOOL</div>
                <div style={{ fontSize: 10, color: 'rgba(255,255,255,0.3)', marginTop: 1 }}>Ishapur, Laxminagar, Mathura · Est. 2009</div>
              </div>
            </div>
            <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.25)' }}>© 2026 Lord Krishna Public School. All rights reserved.</div>
          </div>
        </div>
      </footer>

      {/* ── Registration Modal ── */}
      {regModal && (
        <div onClick={closeReg} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.55)', zIndex: 9998, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16, backdropFilter: 'blur(6px)' }}>
          <div onClick={e => e.stopPropagation()} style={{ background: '#fff', borderRadius: 24, padding: '40px 36px', width: '100%', maxWidth: 460, boxShadow: '0 32px 80px rgba(0,0,0,0.25)', animation: 'pop-in 350ms cubic-bezier(0.34,1.56,0.64,1) both', position: 'relative' }}>
            <button onClick={closeReg} style={{ position: 'absolute', top: 16, right: 16, width: 34, height: 34, borderRadius: '50%', background: '#f1f5f9', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <Icon name="close" size={18} style={{ color: '#64748b' }} />
            </button>

            {regDone ? (
              <div style={{ textAlign: 'center', padding: '16px 0' }}>
                <div style={{ width: 64, height: 64, borderRadius: '50%', background: 'linear-gradient(135deg,#10b981,#059669)', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 20px' }}>
                  <Icon name="check_circle" size={32} style={{ color: '#fff' }} />
                </div>
                <h3 style={{ fontSize: 20, fontWeight: 900, color: '#1e293b', fontFamily: 'Manrope,sans-serif', marginBottom: 10 }}>Registration Received!</h3>
                <p style={{ fontSize: 14, color: '#64748b', lineHeight: 1.7, marginBottom: 28 }}>
                  Thank you, <strong>{regForm.name}</strong>. We've received your enquiry and will contact you on <strong>{regForm.phone}</strong> shortly.
                </p>
                <button className="lp-btn-primary" onClick={closeReg} style={{ width: '100%', justifyContent: 'center', display: 'flex', alignItems: 'center', gap: 6 }}>
                  <Icon name="done" size={16} /> Done
                </button>
              </div>
            ) : (
              <>
                <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 28 }}>
                  <div style={{ width: 48, height: 48, borderRadius: 14, background: 'linear-gradient(135deg,#1960a3,#60a5fa)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                    <Icon name="app_registration" size={24} style={{ color: '#fff' }} />
                  </div>
                  <div>
                    <h3 style={{ fontSize: 18, fontWeight: 900, color: '#1e293b', fontFamily: 'Manrope,sans-serif', lineHeight: 1.2 }}>Student Registration</h3>
                    <p style={{ fontSize: 12, color: '#94a3b8', marginTop: 2 }}>Admission Enquiry · Session 2026–27</p>
                  </div>
                </div>

                <form onSubmit={handleRegSubmit} noValidate>
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 18 }}>
                    <div>
                      <label className="reg-label">Student Name <span style={{ color: '#ef4444' }}>*</span></label>
                      <input className={`reg-input${regErrors.name ? ' err' : ''}`} placeholder="Full name of student"
                        value={regForm.name} onChange={e => setRegForm(f => ({ ...f, name: e.target.value }))} />
                      {regErrors.name && <div className="reg-err"><Icon name="error" size={13} />{regErrors.name}</div>}
                    </div>
                    <div>
                      <label className="reg-label">Phone Number <span style={{ color: '#ef4444' }}>*</span></label>
                      <input className={`reg-input${regErrors.phone ? ' err' : ''}`} placeholder="10-digit mobile number" maxLength={10}
                        value={regForm.phone} onChange={e => setRegForm(f => ({ ...f, phone: e.target.value.replace(/\D/g, '') }))} />
                      {regErrors.phone && <div className="reg-err"><Icon name="error" size={13} />{regErrors.phone}</div>}
                    </div>
                    <div>
                      <label className="reg-label">Email ID <span style={{ color: '#94a3b8', fontWeight: 500, textTransform: 'none', letterSpacing: 0 }}>(optional)</span></label>
                      <input className={`reg-input${regErrors.email ? ' err' : ''}`} placeholder="parent@email.com" type="email"
                        value={regForm.email} onChange={e => setRegForm(f => ({ ...f, email: e.target.value }))} />
                      {regErrors.email && <div className="reg-err"><Icon name="error" size={13} />{regErrors.email}</div>}
                    </div>
                    <button type="submit" className="lp-btn-primary" style={{ width: '100%', justifyContent: 'center', display: 'flex', alignItems: 'center', gap: 8, marginTop: 4 }}>
                      <Icon name="send" size={16} /> Submit Enquiry
                    </button>
                  </div>
                </form>
              </>
            )}
          </div>
        </div>
      )}

      {/* ── Admission Popup ── */}
      {popup && (
        <div onClick={() => setPopup(false)} style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.72)', zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16, backdropFilter: 'blur(6px)' }}>
          <div onClick={e => e.stopPropagation()} style={{ position: 'relative', maxWidth: 480, width: '100%', borderRadius: 20, overflow: 'hidden', boxShadow: '0 32px 80px rgba(0,0,0,0.6)', animation: 'pop-in 400ms cubic-bezier(0.34,1.56,0.64,1) both' }}>
            <button onClick={() => setPopup(false)}
              style={{ position: 'absolute', top: 12, right: 12, width: 36, height: 36, borderRadius: '50%', background: 'rgba(0,0,0,0.55)', border: '2px solid rgba(255,255,255,0.4)', color: '#fff', fontSize: 18, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 10, lineHeight: 1, fontWeight: 700 }}>
              <Icon name="close" size={18} style={{ color: '#fff' }} />
            </button>
            <img src={process.env.PUBLIC_URL + '/brochure.png'} alt="Admission Open - Lord Krishna Public School"
              style={{ width: '100%', display: 'block' }} />
          </div>
        </div>
      )}
    </div>
  );
}
